import { describe, it, expect } from 'vitest';
import { bilateralFilter } from '../src/image-bilateral';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function variance(arr: Float32Array): number {
  let mean = 0;
  for (let i = 0; i < arr.length; i++) mean += arr[i];
  mean /= arr.length;
  let v = 0;
  for (let i = 0; i < arr.length; i++) {
    const d = arr[i] - mean;
    v += d * d;
  }
  return v / arr.length;
}

describe('bilateralFilter', () => {
  it('is identity on a constant plane', () => {
    const W = 32;
    const H = 32;
    const plane = new Float32Array(W * H);
    plane.fill(0.5);

    const out = bilateralFilter({ plane, width: W, height: H });

    for (let i = 0; i < out.length; i++) {
      expect(Math.abs(out[i] - 0.5)).toBeLessThan(1e-6);
    }
  });

  it('smooths noise on a flat region', () => {
    const W = 32;
    const H = 32;
    const rand = lcg(42);
    const plane = new Float32Array(W * H);
    for (let i = 0; i < plane.length; i++) {
      plane[i] = 0.5 + 0.1 * (rand() - 0.5);
    }

    const inVar = variance(plane);
    const out = bilateralFilter({ plane, width: W, height: H });
    const outVar = variance(out);

    expect(outVar).toBeLessThan(inVar * 0.5);
  });

  it('preserves a sharp edge', () => {
    const W = 32;
    const H = 32;
    const plane = new Float32Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        plane[y * W + x] = x < W / 2 ? 0.0 : 1.0;
      }
    }

    const out = bilateralFilter({ plane, width: W, height: H });

    // Pick an interior row well away from top/bottom borders.
    const y = 16;
    expect(Math.abs(out[y * W + 15])).toBeLessThan(0.15);
    expect(Math.abs(out[y * W + 16] - 1)).toBeLessThan(0.15);
  });

  it('returns a fresh Float32Array, not the input', () => {
    const W = 8;
    const H = 8;
    const plane = new Float32Array(W * H);
    plane.fill(0.25);

    const out = bilateralFilter({ plane, width: W, height: H });

    expect(out).toBeInstanceOf(Float32Array);
    expect(out).not.toBe(plane);
    expect(out.buffer).not.toBe(plane.buffer);
  });

  it('throws RangeError on width <= 0', () => {
    const plane = new Float32Array(0);
    expect(() => bilateralFilter({ plane, width: 0, height: 4 })).toThrow(RangeError);
  });

  it('throws RangeError on height <= 0', () => {
    const plane = new Float32Array(0);
    expect(() => bilateralFilter({ plane, width: 4, height: 0 })).toThrow(RangeError);
  });

  it('throws RangeError on plane.length mismatch', () => {
    const plane = new Float32Array(10);
    expect(() => bilateralFilter({ plane, width: 4, height: 4 })).toThrow(RangeError);
  });

  it('throws RangeError on sigmaSpatial <= 0', () => {
    const plane = new Float32Array(16);
    expect(() =>
      bilateralFilter({ plane, width: 4, height: 4, sigmaSpatial: 0 }),
    ).toThrow(RangeError);
    expect(() =>
      bilateralFilter({ plane, width: 4, height: 4, sigmaSpatial: -1 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on sigmaIntensity <= 0', () => {
    const plane = new Float32Array(16);
    expect(() =>
      bilateralFilter({ plane, width: 4, height: 4, sigmaIntensity: 0 }),
    ).toThrow(RangeError);
    expect(() =>
      bilateralFilter({ plane, width: 4, height: 4, sigmaIntensity: -0.1 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on kernelRadius < 0', () => {
    const plane = new Float32Array(16);
    expect(() =>
      bilateralFilter({ plane, width: 4, height: 4, kernelRadius: -1 }),
    ).toThrow(RangeError);
  });

  it('default kernel radius is ceil(3 * sigmaSpatial)', () => {
    // With sigmaSpatial=2 the default radius is 6 -> kernel side 13.
    // We verify by comparing the default-radius result with an explicit
    // kernelRadius=6 call: they must be bitwise identical.
    const W = 16;
    const H = 16;
    const rand = lcg(7);
    const plane = new Float32Array(W * H);
    for (let i = 0; i < plane.length; i++) plane[i] = rand();

    const defaulted = bilateralFilter({
      plane,
      width: W,
      height: H,
      sigmaSpatial: 2,
    });
    const explicit = bilateralFilter({
      plane,
      width: W,
      height: H,
      sigmaSpatial: 2,
      kernelRadius: 6,
    });

    expect(defaulted.length).toBe(explicit.length);
    for (let i = 0; i < defaulted.length; i++) {
      expect(defaulted[i]).toBe(explicit[i]);
    }

    // And confirm a different explicit radius (e.g. 5) produces a
    // different result, proving the default really is 6.
    const radius5 = bilateralFilter({
      plane,
      width: W,
      height: H,
      sigmaSpatial: 2,
      kernelRadius: 5,
    });
    let differs = false;
    for (let i = 0; i < defaulted.length; i++) {
      if (defaulted[i] !== radius5[i]) {
        differs = true;
        break;
      }
    }
    expect(differs).toBe(true);
  });
});
